SELECT COUNT(*) IS_IRU
FROM TBL_MEMBER
WHERE MEMBER_EMAIL = #{memberEmail}

SELECT ID, MEMBER_EMAIL, MEMBER_PASSWORD, MEMBER_NAME
FROM TBL_MEMBER
WHERE MEMBER_EMAIL = #{memberEmail}
	AND MEMBER_PASSWORD = #{memberPassword}

SELECT ID, MEMBER_EMAIL, MEMBER_PASSWORD, MEMBER_NAME
FROM TBL_MEMBER
WHERE ID = #{id}
